+//  Maybe-Flat    Maybe-Flat  Maybe-Flat  Maybe-Flat  Maybe-flat
+TypePtr::FlatInArray TypePtr::meet_flat_in_array(const FlatInArray left, const FlatInArray right) {
+  if (left == TopFlat) {
+    return right;
+  }
+  if (right == TopFlat) {
+    return left;
+  }
+  if (left == MaybeFlat || right == MaybeFlat) {
+    return MaybeFlat;
+  }
+
+  switch (left) {
+    case Flat:
+      if (right == Flat) {
+        return Flat;
+      }
+      return MaybeFlat;
+    case NotFlat:
+      if (right == NotFlat) {
+        return NotFlat;
+      }
+      return MaybeFlat;
+    default:
+      ShouldNotReachHere();
+      return Uninitialized;
+  }
